### Save and Reuse Authentication State in Playwright Tests

Source: https://context7.com/microsoft/playwright/llms.txt

Implement authentication setup tests that capture and persist login state (cookies, localStorage, sessionStorage, IndexedDB) to a JSON file. Subsequent tests can load this saved state to start authenticated, eliminating the need to log in for every test. Includes example using GitHub authentication.

```typescript
// tests/auth.setup.ts
import { test as setup, expect } from '@playwright/test';
import path from 'path';

const authFile = path.join(__dirname, '../playwright/.auth/user.json');

setup('authenticate', async ({ page }) => {
  // Navigate to login page
  await page.goto('https://github.com/login');

  // Perform login
  await page.getByLabel('Username or email address').fill('username');
  await page.getByLabel('Password').fill('password');
  await page.getByRole('button', { name: 'Sign in' }).click();

  // Wait for authentication to complete
  await page.waitForURL('https://github.com/');
  await expect(page.getByRole('button', { name: 'View profile' })).toBeVisible();

  // Save authentication state (including cookies, localStorage, sessionStorage)
  await page.context().storageState({ path: authFile });

  // Save authentication state with IndexedDB (useful for Firebase Auth, etc.)
  await page.context().storageState({ path: authFile, indexedDB: true });
});

// tests/authenticated.spec.ts
import { test, expect } from '@playwright/test';

// This test will start with saved authentication state
test('access protected page', async ({ page }) => {
  await page.goto('https://github.com/settings');

  // User is already authenticated
  await expect(page.getByRole('heading', { name: 'Settings' })).toBeVisible();
});
```

